+    writeAudit(db, { actor, action: 'create', entityType: 'customer', entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+export function updateCustomer(
+  db: DB,
+  id: number,
+  input: UpdateCustomerInput,
+  actor = 'local_user',
+): Customer | null {
+  const before = getCustomer(db, id);
+  if (!before) return null;
+  const next = { ...before, ...normalizeUpdateCustomer(input, before) };
+
+  return db.transaction(() => {
+    db.prepare(
+      `UPDATE customers SET
+         display_name = @displayName,
+         email_hash = @emailHash,
+         email_encrypted = @emailEncrypted,
+         notes = @notes
+       WHERE id = @id`,
+    ).run({
+      id,
+      displayName: next.displayName,
+      emailHash: next.emailHash,
+      emailEncrypted: next.emailEncrypted,
+      notes: next.notes,
+    });
+    const after = getCustomerOrThrow(db, id);
+    writeAudit(db, { actor, action: 'update', entityType: 'customer', entityId: id, before, after });
+    return after;
+  })();
+}
+
+export function deleteCustomer(db: DB, id: number, actor = 'local_user'): boolean {
+  const before = getCustomer(db, id);
+  if (!before) return false;
+  const consents = listConsentHistory(db, id);
+
+  return db.transaction(() => {
+    writeAudit(db, { actor, action: 'delete', entityType: 'customer', entityId: id, before: { ...before, consents } });
+    db.prepare('DELETE FROM customers WHERE id = ?').run(id);
+    return true;
+  })();
+}
+
+export function grantConsent(db: DB, input: GrantConsentInput, actor = 'local_user'): Consent {
+  const payload = normalizeGrantConsent(input);
+  if (!getCustomer(db, payload.customerId)) {
+    throw new Error(`customer not found: ${payload.customerId}`);
+  }
+
+  return db.transaction(() => {
+    const result = db
+      .prepare(
+        `INSERT INTO consents (customer_id, consent_type, consented_at, source, evidence_attachment_id)
+         VALUES (@customerId, @consentType, @consentedAt, @source, @evidenceAttachmentId)`,
+      )
+      .run(payload);
+    const created = getConsentOrThrow(db, Number(result.lastInsertRowid));
+    writeAudit(db, { actor, action: 'create', entityType: 'consent', entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+export function revokeConsent(
+  db: DB,
+  customerId: number,
+  consentId: number,
+  input: RevokeConsentInput,
+  actor = 'local_user',
+): Consent | null {
+  const before = getConsent(db, consentId);
+  if (!before || before.customerId !== customerId) return null;
+  const revokedAt = requireText(input.revokedAt, 'revokedAt');
+
+  return db.transaction(() => {
+    db.prepare('UPDATE consents SET revoked_at = ? WHERE id = ?').run(revokedAt, consentId);
+    const after = getConsentOrThrow(db, consentId);
+    writeAudit(db, { actor, action: 'update', entityType: 'consent', entityId: consentId, before, after });
+    return after;
+  })();
+}
+
+export function listConsentHistory(db: DB, customerId: number): Consent[] {
+  const rows = db
+    .prepare('SELECT * FROM consents WHERE customer_id = ? ORDER BY consented_at ASC, id ASC')
+    .all(customerId) as ConsentRow[];
+  return rows.map(mapConsent);
+}
+
+export function getConsent(db: DB, id: number): Consent | null {
+  const row = db.prepare('SELECT * FROM consents WHERE id = ?').get(id) as ConsentRow | undefined;
+  return row ? mapConsent(row) : null;
+}
+
+function getCustomerOrThrow(db: DB, id: number): Customer {
+  const customer = getCustomer(db, id);
+  if (!customer) throw new Error(`customer not found: ${id}`);
+  return customer;
+}
+
+function getConsentOrThrow(db: DB, id: number): Consent {
+  const consent = getConsent(db, id);
+  if (!consent) throw new Error(`consent not found: ${id}`);
+  return consent;
+}
+
+function normalizeCreateCustomer(input: CreateCustomerInput): CustomerPayload {
+  // 顧客情報は display_name/notes と非平文メール識別子だけに限定する。
+  // raw email は即時ハッシュ化し、返却値・監査ログ・DBのどこにも平文を残さない。
+  const email = normalizeEmailFields(input);
+  return {
+    displayName: requireText(input.displayName, 'displayName'),
+    emailHash: email.emailHash,
+    emailEncrypted: email.emailEncrypted,
+    notes: nullableText(input.notes, 'notes'),
+  };
+}
+
+function normalizeUpdateCustomer(input: UpdateCustomerInput, before: Customer): Partial<CustomerPayload> {
+  const out: Partial<CustomerPayload> = {};
+  if (input.displayName !== undefined) out.displayName = requireText(input.displayName, 'displayName');
+  if (input.notes !== undefined) out.notes = nullableText(input.notes, 'notes');
+  if (input.email !== undefined || input.emailHash !== undefined || input.emailEncrypted !== undefined) {
+    Object.assign(out, normalizeEmailFields(input, before));
+  }
+  return out;
+}
+
+function normalizeGrantConsent(input: GrantConsentInput): Omit<Consent, 'id' | 'revokedAt'> {
+  return {
+    customerId: requirePositiveInteger(input.customerId, 'customerId'),
+    consentType: requireText(input.consentType, 'consentType'),
+    consentedAt: requireText(input.consentedAt, 'consentedAt'),
+    source: nullableText(input.source, 'source'),
+    evidenceAttachmentId: optionalPositiveInteger(input.evidenceAttachmentId, 'evidenceAttachmentId'),
+  };
+}
+
+function normalizeEmailFields(
+  input: Pick<CreateCustomerInput, 'email' | 'emailHash' | 'emailEncrypted'>,
+  before?: Pick<Customer, 'emailHash' | 'emailEncrypted'>,
+): Pick<CustomerPayload, 'emailHash' | 'emailEncrypted'> {
+  if (input.email !== undefined) {
+    const email = nullableText(input.email, 'email');
+    return {
+      emailHash: email ? hashEmail(email) : null,
+      emailEncrypted: input.emailEncrypted !== undefined ? nullableText(input.emailEncrypted, 'emailEncrypted') : null,
+    };
+  }
+  return {
+    emailHash: input.emailHash !== undefined ? nullableText(input.emailHash, 'emailHash') : before?.emailHash ?? null,
+    emailEncrypted:
+      input.emailEncrypted !== undefined ? nullableText(input.emailEncrypted, 'emailEncrypted') : before?.emailEncrypted ?? null,
+  };
+}
+
+function hashEmail(email: string): string {
+  return createHash('sha256').update(email.trim().toLowerCase()).digest('hex');
+}
+
+function requireText(value: unknown, field: string): string {
+  const text = nullableText(value, field);
+  if (!text) throw new Error(`${field} is required`);
+  return text;
+}
+
+function nullableText(value: unknown, field: string): string | null {
+  if (value == null) return null;
+  if (typeof value !== 'string') throw new Error(`${field} must be a string`);
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
+
+function requirePositiveInteger(value: unknown, field: string): number {
+  if (typeof value !== 'number' || !Number.isSafeInteger(value) || value <= 0) {
+    throw new Error(`${field} must be a positive integer`);
+  }
+  return value;
+}
+
+function optionalPositiveInteger(value: unknown, field: string): number | null {
+  if (value == null) return null;
+  return requirePositiveInteger(value, field);
+}
+
+function mapCustomer(row: CustomerRow): Customer {
+  return {
+    id: row.id,
+    displayName: row.display_name ?? '',
+    emailHash: row.email_hash,
+    emailEncrypted: row.email_encrypted,
+    notes: row.notes,
+    createdAt: row.created_at,
+  };
+}
+
+function mapConsent(row: ConsentRow): Consent {
+  return {
+    id: row.id,
+    customerId: row.customer_id,
+    consentType: row.consent_type,
+    consentedAt: row.consented_at,
+    source: row.source,
+    revokedAt: row.revoked_at,
+    evidenceAttachmentId: row.evidence_attachment_id,
+  };
+}
diff --git a/packages/core/test/customers.test.ts b/packages/core/test/customers.test.ts
new file mode 100755
index 0000000000000000000000000000000000000000..7ab74704bf2feaa4fcaf6e3a3aff4fcc410d84b1
--- /dev/null
+++ b/packages/core/test/customers.test.ts
@@ -0,0 +1,147 @@
+import { createHash } from 'node:crypto';
+import { describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import {
+  createCustomer,
+  deleteCustomer,
+  getCustomer,
+  grantConsent,
+  listConsentHistory,
+  listCustomers,
+  revokeConsent,
+  updateCustomer,
+} from '../src/services/customers.js';
+
+describe('customer service', () => {
+  it('stores only minimal customer fields and never persists plaintext email', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    const customer = createCustomer(db, {
+      displayName: '山田 太郎',
+      email: 'Taro@example.com',
+      notes: '請求書は月末締め',
+    });
+    const expectedHash = createHash('sha256').update('taro@example.com').digest('hex');
+
+    expect(customer).toMatchObject({
+      id: expect.any(Number),
+      displayName: '山田 太郎',
+      emailHash: expectedHash,
+      emailEncrypted: null,
+      notes: '請求書は月末締め',
+      createdAt: expect.any(String),
+    });
+    expect(listCustomers(db)).toHaveLength(1);
+    expect(getCustomer(db, customer.id)?.emailHash).toBe(expectedHash);
+
+    const stored = db
+      .prepare('SELECT display_name, email_hash, email_encrypted, notes FROM customers WHERE id = ?')
+      .get(customer.id) as {
+      display_name: string;
+      email_hash: string;
+      email_encrypted: string | null;
+      notes: string;
+    };
+    expect(JSON.stringify(stored)).not.toContain('Taro@example.com');
+    expect(stored.email_hash).toBe(expectedHash);
+
+    const audit = db
+      .prepare('SELECT after_json FROM audit_logs WHERE entity_type = ? AND action = ?')
+      .get('customer', 'create') as { after_json: string };
+    expect(audit.after_json).not.toContain('Taro@example.com');
+    expect(JSON.parse(audit.after_json)).toMatchObject({ emailHash: expectedHash });
+
+    db.close();
+  });
+
+  it('updates and deletes customers with audit logs', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const customer = createCustomer(db, {
+      displayName: '佐藤 花子',
+      emailEncrypted: 'local-ciphertext',
+    });
+
+    const updated = updateCustomer(db, customer.id, {
+      displayName: '佐藤 花子 様',
+      notes: 'メール連絡不可',
+      emailHash: null,
+      emailEncrypted: 'new-local-ciphertext',
+    });
+    expect(updated).toMatchObject({
+      id: customer.id,
+      displayName: '佐藤 花子 様',
+      emailHash: null,
+      emailEncrypted: 'new-local-ciphertext',
+      notes: 'メール連絡不可',
+    });
+
+    expect(deleteCustomer(db, customer.id)).toBe(true);
+    expect(getCustomer(db, customer.id)).toBeNull();
+
+    const audits = db
+      .prepare('SELECT action, before_json, after_json FROM audit_logs WHERE entity_type = ? ORDER BY id ASC')
+      .all('customer') as Array<{ action: string; before_json: string | null; after_json: string | null }>;
+    expect(audits.map((row) => row.action)).toEqual(['create', 'update', 'delete']);
+    expect(JSON.parse(audits[1]?.before_json ?? '{}')).toMatchObject({ displayName: '佐藤 花子' });
+    expect(JSON.parse(audits[1]?.after_json ?? '{}')).toMatchObject({ displayName: '佐藤 花子 様' });
+    expect(JSON.parse(audits[2]?.before_json ?? '{}')).toMatchObject({ displayName: '佐藤 花子 様' });
+
+    db.close();
+  });
+
+  it('grants, revokes, and lists consent history with audit logs', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const customer = createCustomer(db, { displayName: '同意管理 顧客' });
+
+    const marketing = grantConsent(db, {
+      customerId: customer.id,
+      consentType: 'marketing_email',
+      consentedAt: '2026-06-09T10:00:00+09:00',
+      source: 'settings_screen',
+    });
+    grantConsent(db, {
+      customerId: customer.id,
+      consentType: 'terms',
+      consentedAt: '2026-06-09T09:00:00+09:00',
+      source: 'checkout',
+    });
+
+    const revoked = revokeConsent(db, customer.id, marketing.id, {
+      revokedAt: '2026-06-10T12:00:00+09:00',
+    });
+    expect(revoked).toMatchObject({
+      id: marketing.id,
+      customerId: customer.id,
+      consentType: 'marketing_email',
+      revokedAt: '2026-06-10T12:00:00+09:00',
+    });
+
+    expect(listConsentHistory(db, customer.id)).toEqual([
+      expect.objectContaining({ consentType: 'terms', revokedAt: null }),
+      expect.objectContaining({ consentType: 'marketing_email', revokedAt: '2026-06-10T12:00:00+09:00' }),
+    ]);
+    expect(revokeConsent(db, customer.id + 1, marketing.id, { revokedAt: '2026-06-11' })).toBeNull();
+
+    const consentAudits = db
+      .prepare('SELECT action FROM audit_logs WHERE entity_type = ? ORDER BY id ASC')
+      .all('consent') as Array<{ action: string }>;
+    expect(consentAudits.map((row) => row.action)).toEqual(['create', 'create', 'update']);
+
+    db.close();
+  });
+
+  it('rejects invalid customer and consent payloads', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    expect(() => createCustomer(db, { displayName: '' })).toThrow(/displayName is required/);
+    expect(() =>
+      grantConsent(db, {
+        customerId: 999,
+        consentType: 'marketing_email',
+        consentedAt: '2026-06-09T10:00:00+09:00',
+      }),
+    ).toThrow(/customer not found/);
+
+    db.close();
+  });
+});
diff --git a/packages/server/src/routes/customers.ts b/packages/server/src/routes/customers.ts
new file mode 100755
index 0000000000000000000000000000000000000000..9bd56adf17314263e28d1c0c55245cdb47343e8c
--- /dev/null
+++ b/packages/server/src/routes/customers.ts
@@ -0,0 +1,401 @@
+import { createHash } from 'node:crypto';
+import type { FastifyInstance } from 'fastify';
+import { writeAudit, type DB } from '@free-worker/core';
+
+interface Customer {
+  id: number;
+  displayName: string;
+  emailHash: string | null;
+  emailEncrypted: string | null;
+  notes: string | null;
+  createdAt: string;
+}
+
+interface Consent {
+  id: number;
+  customerId: number;
+  consentType: string;
+  consentedAt: string;
+  source: string | null;
+  revokedAt: string | null;
+  evidenceAttachmentId: number | null;
+}
+
+interface CustomerPayload {
+  displayName?: unknown;
+  notes?: unknown;
+  email?: unknown;
+  emailHash?: unknown;
+  emailEncrypted?: unknown;
+}
+
+interface ConsentPayload {
+  consentType?: unknown;
+  consentedAt?: unknown;
+  source?: unknown;
+  evidenceAttachmentId?: unknown;
+  revokedAt?: unknown;
+}
+
+interface CustomerRow {
+  id: number;
+  display_name: string | null;
+  email_hash: string | null;
+  email_encrypted: string | null;
+  notes: string | null;
+  created_at: string;
+}
+
+interface ConsentRow {
+  id: number;
+  customer_id: number;
+  consent_type: string;
+  consented_at: string;
+  source: string | null;
+  revoked_at: string | null;
+  evidence_attachment_id: number | null;
+}
+
+interface IdParams {
+  id: string;
+}
+
+interface ConsentParams extends IdParams {
+  consentId: string;
+}
+
+type CustomerFields = Omit<Customer, 'id' | 'createdAt'>;
+
+export async function customerRoutes(app: FastifyInstance): Promise<void> {
+  app.get('/api/customers', async () => listCustomers(app.db));
+
+  app.get<{ Params: IdParams }>('/api/customers/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const customer = getCustomer(app.db, id);
+    if (!customer) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return customer;
+  });
+
+  app.post<{ Body: CustomerPayload }>('/api/customers', async (req, reply) => {
+    try {
+      const created = createCustomer(app.db, req.body ?? {});
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.put<{ Body: CustomerPayload; Params: IdParams }>('/api/customers/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getCustomer(app.db, id)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    try {
+      return updateCustomer(app.db, id, req.body ?? {});
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.delete<{ Params: IdParams }>('/api/customers/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getCustomer(app.db, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    app.db.transaction(() => {
+      writeAudit(app.db, {
+        action: 'delete',
+        entityType: 'customer',
+        entityId: id,
+        before: { ...before, consents: listConsentHistory(app.db, id) },
+      });
+      app.db.prepare('DELETE FROM customers WHERE id = ?').run(id);
+    })();
+    reply.code(204);
+    return undefined;
+  });
+
+  app.get<{ Params: IdParams }>('/api/customers/:id/consents', async (req, reply) => {
+    const customerId = parseId(req.params.id);
+    if (customerId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getCustomer(app.db, customerId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return listConsentHistory(app.db, customerId);
+  });
+
+  app.post<{ Body: ConsentPayload; Params: IdParams }>('/api/customers/:id/consents', async (req, reply) => {
+    const customerId = parseId(req.params.id);
+    if (customerId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getCustomer(app.db, customerId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    try {
+      const created = grantConsent(app.db, customerId, req.body ?? {});
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.post<{ Body: ConsentPayload; Params: ConsentParams }>(
+    '/api/customers/:id/consents/:consentId/revoke',
+    async (req, reply) => {
+      const customerId = parseId(req.params.id);
+      const consentId = parseId(req.params.consentId);
+      if (customerId == null || consentId == null) {
+        reply.code(400);
+        return { error: 'invalid_id' };
+      }
+      const before = getConsent(app.db, consentId);
+      if (!before || before.customerId !== customerId) {
+        reply.code(404);
+        return { error: 'not_found' };
+      }
+      try {
+        return revokeConsent(app.db, consentId, req.body ?? {});
+      } catch (error) {
+        reply.code(400);
+        return invalidPayload(error);
+      }
+    },
+  );
+}
+
+function listCustomers(db: DB): Customer[] {
+  const rows = db.prepare('SELECT * FROM customers ORDER BY id ASC').all() as CustomerRow[];
+  return rows.map(mapCustomer);
+}
+
+function getCustomer(db: DB, id: number): Customer | null {
+  const row = db.prepare('SELECT * FROM customers WHERE id = ?').get(id) as CustomerRow | undefined;
+  return row ? mapCustomer(row) : null;
+}
+
+function getCustomerOrThrow(db: DB, id: number): Customer {
+  const customer = getCustomer(db, id);
+  if (!customer) throw new Error(`customer not found: ${id}`);
+  return customer;
+}
+
+function createCustomer(db: DB, body: CustomerPayload): Customer {
+  const payload = normalizeCreateCustomer(body);
+  return db.transaction(() => {
+    const result = db
+      .prepare(
+        `INSERT INTO customers (display_name, email_hash, email_encrypted, notes)
+         VALUES (@displayName, @emailHash, @emailEncrypted, @notes)`,
+      )
+      .run(payload);
+    const created = getCustomerOrThrow(db, Number(result.lastInsertRowid));
+    writeAudit(db, { action: 'create', entityType: 'customer', entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+function updateCustomer(db: DB, id: number, body: CustomerPayload): Customer {
+  const before = getCustomerOrThrow(db, id);
+  const next = { ...before, ...normalizeUpdateCustomer(body, before) };
+  return db.transaction(() => {
+    db.prepare(
+      `UPDATE customers SET
+         display_name = @displayName,
+         email_hash = @emailHash,
+         email_encrypted = @emailEncrypted,
+         notes = @notes
+       WHERE id = @id`,
+    ).run({
+      id,
+      displayName: next.displayName,
+      emailHash: next.emailHash,
+      emailEncrypted: next.emailEncrypted,
+      notes: next.notes,
+    });
+    const after = getCustomerOrThrow(db, id);
+    writeAudit(db, { action: 'update', entityType: 'customer', entityId: id, before, after });
+    return after;
+  })();
+}
+
+function grantConsent(db: DB, customerId: number, body: ConsentPayload): Consent {
+  const payload = normalizeConsent(customerId, body);
+  return db.transaction(() => {
+    const result = db
+      .prepare(
+        `INSERT INTO consents (customer_id, consent_type, consented_at, source, evidence_attachment_id)
+         VALUES (@customerId, @consentType, @consentedAt, @source, @evidenceAttachmentId)`,
+      )
+      .run(payload);
+    const created = getConsentOrThrow(db, Number(result.lastInsertRowid));
+    writeAudit(db, { action: 'create', entityType: 'consent', entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+function revokeConsent(db: DB, consentId: number, body: ConsentPayload): Consent {
+  const before = getConsentOrThrow(db, consentId);
+  const revokedAt = requireText(body.revokedAt, 'revokedAt');
+  return db.transaction(() => {
+    db.prepare('UPDATE consents SET revoked_at = ? WHERE id = ?').run(revokedAt, consentId);
+    const after = getConsentOrThrow(db, consentId);
+    writeAudit(db, { action: 'update', entityType: 'consent', entityId: consentId, before, after });
+    return after;
+  })();
+}
+
+function listConsentHistory(db: DB, customerId: number): Consent[] {
+  const rows = db
+    .prepare('SELECT * FROM consents WHERE customer_id = ? ORDER BY consented_at ASC, id ASC')
+    .all(customerId) as ConsentRow[];
+  return rows.map(mapConsent);
+}
+
